INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1517, 196155, 10, 1969, '三阳开泰', '三阳开泰：谓冬去春来，阴消阳长，万事吉祥亨通。旧时用为新年祝颂之辞。《周易》爻象有二，--为阴爻，―为阳爻。旧历十一月为复卦，一阳生于下；十二月为临卦，二阳生于下；正月为泰卦，三阳生于下。“三阳开泰”即由此而来。亦作“三阳交泰”。《宋史&#183;乐志》：“三阳交泰，日新惟良。”张居正《贺元旦表》：“兹者当三阳开泰之候，正万物出震之时。”', '三阳开泰：谓冬去春来，阴消阳长，万事吉祥亨通。旧时用为新年祝颂之辞。《周易》爻象有二，--为阴爻，―为阳爻。旧历十一月为复卦，一阳生于下；十二月为临卦，二阳生于下；正月为泰卦，三阳生于下。“三阳开泰”即由此而来。亦作“三阳交泰”。《宋史·乐志》：“三阳交泰，日新惟良。”张居正《贺元旦表》：“兹者当三阳开泰之候，正万物出震之时。”', NULL, '2003-02-13 10:21:00', 4, '20030312132100_bbsid_196155_board_10_d766f07517.html', '20030312132100');
